function pt(v: number, ts?: number): KpiDataPoint { return { value: v, timestamp: ts ?? 1000000 }; }
function pts(vals: number[]): KpiDataPoint[] { return vals.map((v,i) => ({ value: v, timestamp: 1000000 + i * 1000 })); }
