describe('averageValue', () => { it('0e',()=>expect(averageValue([])).toBe(0)); it('s50',()=>expect(averageValue([pt(50)])).toBe(50)); it('a50',()=>expect(averageValue([pt(40),pt(60)])).toBe(50)); it('a20',()=>expect(averageValue([pt(10),pt(20),pt(30)])).toBeCloseTo(20)); it('az',()=>expect(averageValue([pt(0),pt(0),pt(0)])).toBe(0)); it('anz',()=>expect(averageValue([pt(-10),pt(10)])).toBe(0)); it('a1',()=>expect(averageValue([pt(1)])).toBeCloseTo(1)); it('a1.5',()=>expect(averageValue([pt(1),pt(2)])).toBeCloseTo(1.5)); it('a2',()=>expect(averageValue([pt(1),pt(2),pt(3)])).toBeCloseTo(2)); it('a2.5',()=>expect(averageValue([pt(1),pt(2),pt(3),pt(4)])).toBeCloseTo(2.5)); it('a3',()=>expect(averageValue([pt(1),pt(2),pt(3),pt(4),pt(5)])).toBeCloseTo(3)); it('a5.5',()=>expect(averageValue(Array.from({length:10},(_,i)=>pt(i+1)))).toBeCloseTo(5.5)); it('a10.5',()=>expect(averageValue(Array.from({length:20},(_,i)=>pt(i+1)))).toBeCloseTo(10.5)); it('a50.5',()=>expect(averageValue(Array.from({length:100},(_,i)=>pt(i+1)))).toBeCloseTo(50.5)); it('a500',()=>{const ps=Array.from({length:1000},(_,i)=>pt(i+1));expect(averageValue(ps)).toBeCloseTo(500.5);}); it('a3.5',()=>expect(averageValue([pt(1),pt(2),pt(3),pt(4),pt(5),pt(6)])).toBeCloseTo(3.5)); it('a4',()=>expect(averageValue([pt(1),pt(2),pt(3),pt(4),pt(5),pt(6),pt(7)])).toBeCloseTo(4)); it('a5b',()=>expect(averageValue([pt(2),pt(4),pt(6),pt(8)])).toBeCloseTo(5)); it('an0',()=>expect(averageValue([pt(-20),pt(-10),pt(0),pt(10),pt(20)])).toBeCloseTo(0)); it('alg',()=>expect(averageValue([pt(100000),pt(200000)])).toBeCloseTo(150000)); });
describe('minValue', () => { it('null',()=>expect(minValue([])).toBeNull()); it('s',()=>expect(minValue([pt(50)])).toBe(50)); it('m2',()=>expect(minValue([pt(10),pt(20)])).toBe(10)); it('m3',()=>expect(minValue([pt(30),pt(10),pt(20)])).toBe(10)); it('neg',()=>expect(minValue([pt(-5),pt(5)])).toBe(-5)); it('eq',()=>expect(minValue([pt(7),pt(7),pt(7)])).toBe(7)); it('desc',()=>expect(minValue([pt(100),pt(50),pt(25),pt(5)])).toBe(5)); it('asc',()=>expect(minValue([pt(1),pt(2),pt(3),pt(4),pt(5)])).toBe(1)); it('nn',()=>expect(minValue([pt(-1),pt(-5),pt(-3)])).toBe(-5)); it('z',()=>expect(minValue([pt(0),pt(5),pt(10)])).toBe(0)); it('10p',()=>expect(minValue(Array.from({length:10},(_,i)=>pt(i+1)))).toBe(1)); it('20p',()=>expect(minValue(Array.from({length:20},(_,i)=>pt(i+1)))).toBe(1)); it('50p',()=>expect(minValue(Array.from({length:50},(_,i)=>pt(i+1)))).toBe(1)); it('lrg',()=>expect(minValue([pt(1000000),pt(1),pt(500000)])).toBe(1)); it('flt',()=>expect(minValue([pt(1.5),pt(1.1),pt(1.9)])).toBeCloseTo(1.1)); });
