describe('edge cases', () => { it('vp_sm',()=>expect(computeVariancePct(0.11,0.1)).toBeCloseTo(10)); it('lb_at',()=>expect(computePerformance(100,100,'lower_better')).toBe(100)); it('sk',()=>{const d=buildDashboard([makeKpi('x','X','higher_better',100)],{x:pts([100])});expect(d.overall).toBe(100);}); it('lv100',()=>{const ps=Array.from({length:100},(_,i)=>({value:i,timestamp:i*1000}));expect(latestValue(ps)).toBe(99);}); it('mm',()=>{const ps=[pt(10),pt(50),pt(30),pt(5),pt(80)];expect(minValue(ps)).toBe(5);expect(maxValue(ps)).toBe(80);}); it('avg1k',()=>{const ps=Array.from({length:1000},(_,i)=>pt(i+1));expect(averageValue(ps)).toBeCloseTo(500.5);}); it('cli',()=>expect(clampPerformance(Infinity)).toBe(100)); it('cln',()=>expect(clampPerformance(-Infinity)).toBe(0)); it('vf',()=>expect(computeVariance(0.1+0.2,0.3)).toBeCloseTo(0)); it('sp',()=>{const k=makeKpi('k','K','higher_better',100);expect(evaluateKpi(k,[{value:75,timestamp:Date.now()}]).current).toBe(75);}); it('de0',()=>{const ks=[makeKpi('a','A','higher_better',100),makeKpi('b','B','higher_better',100)];expect(buildDashboard(ks,{}).overall).toBe(0);}); it('tst',()=>{const p=[{value:100.0,timestamp:1000},{value:100.001,timestamp:2000}];expect(computeTrend(p)).toBe('stable');}); it('idf',()=>expect(isValidDirection('123')).toBe(false)); it('isf',()=>expect(isValidStatus('1')).toBe(false)); it('iff',()=>expect(isValidFrequency('')).toBe(false)); it('mnu',()=>expect(makePoint(10).notes).toBeUndefined()); it('t0on',()=>expect(computeStatus(100,{value:100,tolerance:0},'target')).toBe('on_track')); it('t0ar',()=>expect(computeStatus(101,{value:100,tolerance:0},'target')).toBe('off_track')); it('c-1',()=>expect(clampPerformance(-1)).toBe(0)); it('c101',()=>expect(clampPerformance(101)).toBe(100)); it('vnn',()=>expect(computeVariance(-50,-50)).toBe(0)); it('vpnn',()=>expect(computeVariancePct(-50,-50)).toBe(0)); it('ht0',()=>expect(computePerformance(0,0,'higher_better')).toBe(100)); it('lt0',()=>expect(computePerformance(0,100,'lower_better')).toBe(100)); it('tt0',()=>expect(computePerformance(50,50,'target')).toBe(100)); });
describe('integration', () => { const kpis=[makeKpi('rev','Revenue','higher_better',100000,'GBP','monthly'),makeKpi('def','Defects','lower_better',2,'%','weekly'),makeKpi('sat','Satisfaction','target',90,'score','monthly'),makeKpi('upt','Uptime','higher_better',99.9,'%','daily'),makeKpi('inc','Incidents','lower_better',0,'count','monthly')]; it('ron',()=>expect(evaluateKpi(kpis[0],pts([100000])).status).toBe('on_track')); it('rex',()=>expect(evaluateKpi(kpis[0],pts([120000])).status).toBe('exceeded')); it('don',()=>expect(evaluateKpi(kpis[1],pts([1])).status).toBe('on_track')); it('son',()=>expect(evaluateKpi(kpis[2],pts([90])).status).toBe('on_track')); it('uoff',()=>expect(['at_risk','off_track']).toContain(evaluateKpi(kpis[3],pts([95])).status)); it('fall5',()=>{const pm={rev:pts([100000]),def:pts([1]),sat:pts([90]),upt:pts([99.9]),inc:pts([0])};const d=buildDashboard(kpis,pm);expect(d.onTrackCount).toBe(5);}); it('onum',()=>{const pm={rev:pts([80000]),def:pts([3]),sat:pts([85]),upt:pts([99]),inc:pts([1])};const d=buildDashboard(kpis,pm);expect(typeof d.overall).toBe('number');}); it('orng',()=>{const pm={rev:pts([80000]),def:pts([3]),sat:pts([85]),upt:pts([99]),inc:pts([1])};const d=buildDashboard(kpis,pm);expect(d.overall).toBeGreaterThanOrEqual(0);expect(d.overall).toBeLessThanOrEqual(100);}); it('wup',()=>{const wp=Array.from({length:7},(_,i)=>({value:90+i*2,timestamp:Date.now()-(7-i)*86400000}));expect(computeTrend(wp)).toBe('up');}); it('wdn',()=>{const wp=Array.from({length:7},(_,i)=>({value:100-i*3,timestamp:Date.now()-(7-i)*86400000}));expect(computeTrend(wp)).toBe('down');}); it('Q1',()=>{const pm={rev:pts([85000]),def:pts([1.5]),sat:pts([88]),upt:pts([99.5]),inc:pts([0])};const d=buildDashboard(kpis,pm);expect(d.kpis).toHaveLength(5);}); it('Q2',()=>{const pm={rev:pts([90000]),def:pts([1.5]),sat:pts([88]),upt:pts([99.5]),inc:pts([0])};const d=buildDashboard(kpis,pm);expect(d.kpis).toHaveLength(5);}); it('Q3',()=>{const pm={rev:pts([95000]),def:pts([1.5]),sat:pts([88]),upt:pts([99.5]),inc:pts([0])};const d=buildDashboard(kpis,pm);expect(d.kpis).toHaveLength(5);}); it('Q4',()=>{const pm={rev:pts([100000]),def:pts([1.5]),sat:pts([88]),upt:pts([99.5]),inc:pts([0])};const d=buildDashboard(kpis,pm);expect(d.kpis).toHaveLength(5);}); it('m1',()=>{const r=evaluateKpi(kpis[0],pts([81000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m2',()=>{const r=evaluateKpi(kpis[0],pts([82000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m3',()=>{const r=evaluateKpi(kpis[0],pts([83000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m4',()=>{const r=evaluateKpi(kpis[0],pts([84000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m5',()=>{const r=evaluateKpi(kpis[0],pts([85000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m6',()=>{const r=evaluateKpi(kpis[0],pts([90000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m7',()=>{const r=evaluateKpi(kpis[0],pts([95000]));expect(r.performance).toBeGreaterThanOrEqual(0);}); it('m8',()=>{const r=evaluateKpi(kpis[0],pts([100000]));expect(r.performance).toBe(100);}); });
