describe('extra_variance', () => {
  it('ev1', () => expect(computeVariance(200, 100)).toBe(100));
  it('ev2', () => expect(computeVariance(50, 200)).toBe(-150));
  it('ev3', () => expect(computeVariance(0, 0)).toBe(0));
  it('ev4', () => expect(computeVariance(-5, 5)).toBe(-10));
  it('ev5', () => expect(computeVariancePct(110, 100)).toBe(10));
  it('ev6', () => expect(computeVariancePct(90, 100)).toBe(-10));
  it('ev7', () => expect(computeStatus(100, {value: 100}, 'higher_better')).toBe('on_track'));
  it('ev8', () => expect(computePerformance(100, 100, 'higher_better')).toBe(100));
  it('ev9', () => expect(computeTrend(pts([90, 100]))).toBe('up'));
  it('ev10', () => expect(computeTrend(pts([100, 90]))).toBe('down'));
  it('ev11', () => expect(latestValue([pt(42, 999)])).toBe(42));
  it('ev12', () => expect(averageValue([pt(10), pt(20), pt(30)])).toBeCloseTo(20));
  it('ev13', () => expect(minValue([pt(3), pt(1), pt(2)])).toBe(1));
  it('ev14', () => expect(maxValue([pt(3), pt(1), pt(2)])).toBe(3));
  it('ev15', () => expect(isValidDirection('higher_better')).toBe(true));
  it('ev16', () => expect(isValidStatus('on_track')).toBe(true));
  it('ev17', () => expect(isValidFrequency('monthly')).toBe(true));
  it('ev18', () => expect(makeKpi('x', 'Y', 'target', 42).target.value).toBe(42));
  it('ev19', () => expect(makePoint(99).value).toBe(99));
  it('ev20', () => expect(clampPerformance(55)).toBe(55));
});
